PRAGMA foreign_keys = ON;
CREATE TABLE IF NOT EXISTS admins(id INTEGER PRIMARY KEY, username TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, salt TEXT NOT NULL, role TEXT NOT NULL DEFAULT 'admin', created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS users(id INTEGER PRIMARY KEY, openid TEXT UNIQUE, nickname TEXT NOT NULL, avatar TEXT, phone TEXT UNIQUE, status TEXT DEFAULT 'active', created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS categories(id INTEGER PRIMARY KEY, name TEXT NOT NULL, parent_id INTEGER REFERENCES categories(id), image TEXT, sort_order INTEGER DEFAULT 0, status TEXT DEFAULT 'active');
CREATE TABLE IF NOT EXISTS pets(id INTEGER PRIMARY KEY, name TEXT NOT NULL, category_id INTEGER REFERENCES categories(id), breed TEXT NOT NULL, gender TEXT, age_months INTEGER, color TEXT, body_type TEXT, personality TEXT, health_status TEXT, vaccine_record TEXT, father_info TEXT, mother_info TEXT, description TEXT, price INTEGER NOT NULL, seller_name TEXT, status TEXT DEFAULT 'draft', created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS pet_skus(id INTEGER PRIMARY KEY, pet_id INTEGER NOT NULL REFERENCES pets(id) ON DELETE CASCADE, sku_name TEXT NOT NULL, price INTEGER NOT NULL, stock INTEGER NOT NULL DEFAULT 1, status TEXT DEFAULT 'active');
CREATE TABLE IF NOT EXISTS pet_images(id INTEGER PRIMARY KEY, pet_id INTEGER NOT NULL REFERENCES pets(id) ON DELETE CASCADE, url TEXT NOT NULL, type TEXT DEFAULT 'gallery', sort_order INTEGER DEFAULT 0);
CREATE TABLE IF NOT EXISTS pet_videos(id INTEGER PRIMARY KEY, pet_id INTEGER NOT NULL REFERENCES pets(id) ON DELETE CASCADE, url TEXT NOT NULL, cover_url TEXT, duration INTEGER DEFAULT 0);
CREATE TABLE IF NOT EXISTS addresses(id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), name TEXT NOT NULL, phone TEXT NOT NULL, province TEXT, city TEXT, district TEXT, detail TEXT NOT NULL, is_default INTEGER DEFAULT 0);
CREATE TABLE IF NOT EXISTS orders(id INTEGER PRIMARY KEY, order_no TEXT UNIQUE NOT NULL, user_id INTEGER NOT NULL REFERENCES users(id), total_amount INTEGER NOT NULL, payment_status TEXT DEFAULT 'unpaid', status TEXT DEFAULT 'pending_payment', address_snapshot TEXT NOT NULL, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS order_items(id INTEGER PRIMARY KEY, order_id INTEGER NOT NULL REFERENCES orders(id) ON DELETE CASCADE, pet_id INTEGER NOT NULL REFERENCES pets(id), sku_id INTEGER REFERENCES pet_skus(id), pet_snapshot TEXT NOT NULL, price INTEGER NOT NULL, quantity INTEGER DEFAULT 1);
CREATE TABLE IF NOT EXISTS logistics(id INTEGER PRIMARY KEY, order_id INTEGER UNIQUE NOT NULL REFERENCES orders(id), company TEXT, tracking_no TEXT, status TEXT DEFAULT 'pending', progress TEXT DEFAULT '[]', updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS complaints(id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), order_id INTEGER REFERENCES orders(id), title TEXT NOT NULL, content TEXT NOT NULL, reply TEXT, status TEXT DEFAULT 'pending', created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS after_sales(id INTEGER PRIMARY KEY, order_id INTEGER NOT NULL REFERENCES orders(id), user_id INTEGER NOT NULL REFERENCES users(id), type TEXT NOT NULL, reason TEXT NOT NULL, amount INTEGER DEFAULT 0, result TEXT, status TEXT DEFAULT 'pending', created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS favorites(id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), pet_id INTEGER NOT NULL REFERENCES pets(id), created_at TEXT DEFAULT CURRENT_TIMESTAMP, UNIQUE(user_id,pet_id));
CREATE TABLE IF NOT EXISTS follows(id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), seller_name TEXT NOT NULL, created_at TEXT DEFAULT CURRENT_TIMESTAMP, UNIQUE(user_id,seller_name));
CREATE TABLE IF NOT EXISTS footprints(id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), pet_id INTEGER NOT NULL REFERENCES pets(id), viewed_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS coupons(id INTEGER PRIMARY KEY, title TEXT NOT NULL, amount INTEGER NOT NULL, threshold INTEGER DEFAULT 0, expires_at TEXT, status TEXT DEFAULT 'active');
CREATE TABLE IF NOT EXISTS user_coupons(id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), coupon_id INTEGER NOT NULL REFERENCES coupons(id), status TEXT DEFAULT 'available');
CREATE TABLE IF NOT EXISTS messages(id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), sender TEXT NOT NULL, type TEXT DEFAULT 'service', content TEXT NOT NULL, is_read INTEGER DEFAULT 0, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS banners(id INTEGER PRIMARY KEY, title TEXT, image TEXT NOT NULL, link TEXT, sort_order INTEGER DEFAULT 0, status TEXT DEFAULT 'active');
CREATE INDEX IF NOT EXISTS idx_pets_search ON pets(status, category_id, breed, name);
CREATE INDEX IF NOT EXISTS idx_orders_user_status ON orders(user_id,status,created_at);
CREATE INDEX IF NOT EXISTS idx_messages_user ON messages(user_id,created_at);
